#include <vector>
#include <algorithm>

using namespace std;

long long solve(vector<long long> prices, vector<long long> strategy, long long k) {
    long long n = prices.size();
    long long original_profit = 0;
    for (long long i = 0; i < n; ++i) {
        original_profit += strategy[i] * prices[i];
    }

    long long max_profit = original_profit;
    long long half_k = k / 2;

    // Precompute the difference if we modify the window starting at i
    vector<long long> diff(n, 0);
    for (long long i = 0; i < n; ++i) {
        if (i < half_k) {
            diff[0] += (0 - strategy[i]) * prices[i];
        } else {
            diff[i - half_k + 1] += (1 - strategy[i]) * prices[i];
        }
    }

    // Compute the sliding window sum of the first half_k elements
    vector<long long> window_sum(n - k + 1, 0);
    long long current_sum = 0;
    for (long long i = 0; i < k; ++i) {
        if (i < half_k) {
            current_sum += (0 - strategy[i]) * prices[i];
        } else {
            current_sum += (1 - strategy[i]) * prices[i];
        }
    }
    window_sum[0] = current_sum;

    for (long long i = 1; i <= n - k; ++i) {
        current_sum -= (0 - strategy[i - 1]) * prices[i - 1];
        current_sum -= (1 - strategy[i + half_k - 1]) * prices[i + half_k - 1];

        current_sum += (0 - strategy[i + k - half_k - 1]) * prices[i + k - half_k - 1];
        current_sum += (1 - strategy[i + k - 1]) * prices[i + k - 1];

        window_sum[i] = current_sum;
    }

    for (long long i = 0; i <= n - k; ++i) {
        long long potential_profit = original_profit + window_sum[i];
        if (potential_profit > max_profit) {
            max_profit = potential_profit;
        }
    }

    return max_profit;
}

