public static long solve(long[] prices, long[] strategy, long k) {
    int n = prices.length;
    long originalProfit = 0;
    for (int i = 0; i < n; i++) {
        originalProfit += strategy[i] * prices[i];
    }

    long maxProfit = originalProfit;
    int halfK = (int) (k / 2);

    // Precompute the difference for each possible window
    long[] windowDiff = new long[n - (int)k + 1];

    // Compute the first window
    long currentDiff = 0;
    for (int i = 0; i < k; i++) {
        if (i < halfK) {
            currentDiff += (0 - strategy[i]) * prices[i];
        } else {
            currentDiff += (1 - strategy[i]) * prices[i];
        }
    }
    windowDiff[0] = currentDiff;

    // Slide the window to compute the rest
    for (int i = 1; i <= n - k; i++) {
        // Remove the contribution of the element leaving the window
        if (i - 1 < halfK) {
            currentDiff -= (0 - strategy[i - 1]) * prices[i - 1];
        } else {
            currentDiff -= (1 - strategy[i - 1]) * prices[i - 1];
        }

        // Add the contribution of the new element entering the window
        int newPos = i + (int)k - 1;
        if (newPos < i + halfK) {
            currentDiff += (0 - strategy[newPos]) * prices[newPos];
        } else {
            currentDiff += (1 - strategy[newPos]) * prices[newPos];
        }

        windowDiff[i] = currentDiff;
    }

    // Find the maximum possible profit
    for (int i = 0; i <= n - k; i++) {
        long potentialProfit = originalProfit + windowDiff[i];
        if (potentialProfit > maxProfit) {
            maxProfit = potentialProfit;
        }
    }

    return maxProfit;
}
